const getLinksByFiles = `-- name: GetLinksByFiles :many
SELECT DISTINCT to_file FROM links WHERE from_file IN (/*SLICE:from_files*/?) ORDER BY to_file
`

func (q *Queries) GetLinksByFiles(ctx context.Context, fromFiles []string) ([]string, error) {
	query := getLinksByFiles
	var queryParams []interface{}
	if len(fromFiles) > 0 {
		for _, v := range fromFiles {
			queryParams = append(queryParams, v)
		}
		query = strings.Replace(query, "/*SLICE:from_files*/?", strings.Repeat(",?", len(fromFiles))[1:], 1)
	} else {
		query = strings.Replace(query, "/*SLICE:from_files*/?", "NULL", 1)
	}
	rows, err := q.db.QueryContext(ctx, query, queryParams...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []string
	for rows.Next() {
		var to_file string
		if err := rows.Scan(&to_file); err != nil {
			return nil, err
		}
		items = append(items, to_file)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

